@@ -0,0 +1,30 @@
+package com.qihoo.finance.aps.common.prometheus.measure;
+
+/**
+ * Central definition for Prometheus measure keys.
+ *
+ * <p>Business scenarios must add stable low-cardinality keys here before using
+ * {@link MeasureUtil}. Dynamic values such as orderNo, userNo, URL, requestId,
+ * or raw error messages must not become measure keys.</p>
+ */
+public enum MeasureKeyEnum {
+
+    PROMETHEUS_MEASURE_MONITOR_SELF_TEST("prometheus_measure_monitor_self_test");
+
+    private final String key;
+
+    MeasureKeyEnum(String key) {
+        if (isBlank(key)) {
+            throw new IllegalArgumentException("measure key must not be blank");
+        }
+        this.key = key;
+    }
+
+    public String getKey() {
+        return key;
+    }
+
+    private static boolean isBlank(String value) {
+        return value == null || value.trim().isEmpty();
+    }
+}

