@@ -0,0 +1,53 @@
+package com.qihoo.finance.aps.common.prometheus.measure;
+
+import com.qihoo.finance.aps.common.prometheus.MetricsHolder;
+import io.micrometer.core.instrument.Counter;
+import lombok.extern.slf4j.Slf4j;
+
+/**
+ * Utility for recording one final result for a measured operation.
+ */
+@Slf4j
+public final class MeasureUtil {
+
+    private MeasureUtil() {
+    }
+
+    public static void record(MeasureKeyEnum measureKey, MeasureResultEnum result) {
+        if (measureKey == null || result == null) {
+            log.warn("PRO [Measure] ignore record because measureKey or result is null, measureKey={}, result={}",
+                measureKey, result);
+            return;
+        }
+
+        try {
+            Counter counter = MetricsHolder.getOrAddMeasureCounter(measureKey, result);
+            if (counter != null) {
+                counter.increment();
+            }
+        } catch (Exception e) {
+            log.error("ERR [Measure] record measure failed, measureKey={}, result={}",
+                measureKey.getKey(), result.getResult(), e);
+        }
+    }
+
+    public static void success(MeasureKeyEnum measureKey) {
+        record(measureKey, MeasureResultEnum.SUCCESS);
+    }
+
+    public static void bizError(MeasureKeyEnum measureKey) {
+        record(measureKey, MeasureResultEnum.BIZ_ERROR);
+    }
+
+    public static void sysError(MeasureKeyEnum measureKey) {
+        record(measureKey, MeasureResultEnum.SYS_ERROR);
+    }
+
+    public static void timeout(MeasureKeyEnum measureKey) {
+        record(measureKey, MeasureResultEnum.TIMEOUT);
+    }
+
+    public static void unknownError(MeasureKeyEnum measureKey) {
+        record(measureKey, MeasureResultEnum.UNKNOWN_ERROR);
+    }
+}

--- a/aps-app/src/test/java/com/qihoo/finance/aps/common/prometheus/measure/MeasureUtilTest.java
+++ b/aps-app/src/test/java/com/qihoo/finance/aps/common/prometheus/measure/MeasureUtilTest.java
@@ -0,0 +1,81 @@
+package com.qihoo.finance.aps.common.prometheus.measure;
+
+import com.qihoo.finance.aps.common.prometheus.MetricsHolder;
+import org.junit.Assert;
+import org.junit.Test;
+
+import java.util.ArrayList;
+import java.util.List;
+import java.util.concurrent.CountDownLatch;
+import java.util.concurrent.ExecutorService;
+import java.util.concurrent.Executors;
+import java.util.concurrent.TimeUnit;
+
+public class MeasureUtilTest {
+
+    @Test
+    public void shouldRecordSupportedMeasureResults() {
+        MeasureUtil.success(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+        MeasureUtil.success(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+        MeasureUtil.timeout(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+        MeasureUtil.bizError(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+        MeasureUtil.sysError(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+        MeasureUtil.unknownError(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+
+        String scrape = MetricsHolder.scrape();
+
+        Assert.assertTrue(scrape.contains("aps_measure_calls_total"));
+        Assert.assertTrue(scrape.contains("measure_key=\"prometheus_measure_monitor_self_test\""));
+        Assert.assertTrue(scrape.contains("result=\"success\""));
+        Assert.assertTrue(scrape.contains("result=\"timeout\""));
+        Assert.assertTrue(scrape.contains("result=\"biz_error\""));
+        Assert.assertTrue(scrape.contains("result=\"sys_error\""));
+        Assert.assertTrue(scrape.contains("result=\"unknown_error\""));
+    }
+
+    @Test
+    public void shouldIgnoreUnsupportedOrBlankInputs() {
+        MetricsHolder.getOrAddMeasureCounter(null, MeasureResultEnum.SUCCESS);
+        MetricsHolder.getOrAddMeasureCounter(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST, null);
+
+        MeasureUtil.record(null, MeasureResultEnum.SUCCESS);
+        MeasureUtil.record(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST, null);
+
+        String scrape = MetricsHolder.scrape();
+
+        Assert.assertFalse(scrape.contains("measure_key=\"\""));
+        Assert.assertFalse(scrape.contains("result=\"\""));
+    }
+
+    @Test
+    public void shouldSupportConcurrentFirstUse() throws Exception {
+        int threadCount = 16;
+        ExecutorService executorService = Executors.newFixedThreadPool(threadCount);
+        CountDownLatch startLatch = new CountDownLatch(1);
+        CountDownLatch finishLatch = new CountDownLatch(threadCount);
+        List<Throwable> errors = new ArrayList<>();
+
+        for (int i = 0; i < threadCount; i++) {
+            executorService.submit(() -> {
+                try {
+                    startLatch.await();
+                    MeasureUtil.timeout(MeasureKeyEnum.PROMETHEUS_MEASURE_MONITOR_SELF_TEST);
+                } catch (Throwable e) {
+                    synchronized (errors) {
+                        errors.add(e);
+                    }
+                } finally {
+                    finishLatch.countDown();
+                }
+            });
+        }
+
+        startLatch.countDown();
+        boolean finished = finishLatch.await(5, TimeUnit.SECONDS);
+        executorService.shutdownNow();
+
+        Assert.assertTrue(finished);
+        Assert.assertTrue(errors.isEmpty());
+        Assert.assertTrue(MetricsHolder.scrape().contains("result=\"timeout\""));
+    }
+}

