+package com.qihoo.finance.aps.common.task.service;
+
+import com.ctrip.framework.apollo.spring.annotation.ApolloJsonValue;
+import com.qihoo.finance.aps.v4.utils.StringUtil;
+import lombok.extern.slf4j.Slf4j;
+import org.apache.commons.collections.MapUtils;
+import org.springframework.beans.factory.annotation.Value;
+import org.springframework.stereotype.Service;
+import org.springframework.util.CollectionUtils;
+
+import java.util.Collections;
+import java.util.List;
+import java.util.Map;
+
+@Slf4j
+@Service
+public class ScheduledTaskExecutorResolver {
+    public static final String TASK_DEFAULT_POOL = "task_default_pool";
+    public static final String TASK_SCHEDULE_DEFAULT_POOL = "aps_task_execute_pool";
+
+    @Value("${aps.apollo.function.switch.taskScheduleExecuteOptimizeSwitch:false}")
+    private boolean taskScheduleExecuteOptimizeSwitch;
+
+    @Value("${aps.apollo.function.switch.taskScheduleParamPoolSwitch:false}")
+    private boolean taskScheduleParamPoolSwitch;
+
+    @Value("${aps.apollo.config.taskScheduleDefaultPoolName:aps_task_execute_pool}")
+    private String taskScheduleDefaultPoolName = TASK_SCHEDULE_DEFAULT_POOL;
+
+    @ApolloJsonValue("${aps.apollo.config.taskSchedulePoolNameMap:{}}")
+    private Map<String, String> taskSchedulePoolNameMap = Collections.emptyMap();
+
+    @ApolloJsonValue("${aps.apollo.config.taskScheduleAllowedPoolNames:[\"aps_task_execute_pool\"]}")
+    private List<String> taskScheduleAllowedPoolNames = Collections.singletonList(TASK_SCHEDULE_DEFAULT_POOL);
+
+    public boolean isOptimizeEnabled() {
+        return taskScheduleExecuteOptimizeSwitch;
+    }
+
+    public String resolvePoolName(String taskName, String taskPoolName) {
+        if (taskScheduleParamPoolSwitch) {
+            String allowedTaskPoolName = resolveAllowedPoolName(taskName, taskPoolName, "task param");
+            if (StringUtil.isNotEmpty(allowedTaskPoolName)) {
+                return allowedTaskPoolName;
+            }
+        }
+
+        String mappedPoolName = MapUtils.isEmpty(taskSchedulePoolNameMap) ? null : taskSchedulePoolNameMap.get(taskName);
+        String allowedMappedPoolName = resolveAllowedPoolName(taskName, mappedPoolName, "apollo map");
+        if (StringUtil.isNotEmpty(allowedMappedPoolName)) {
+            return allowedMappedPoolName;
+        }
+
+        String allowedDefaultPoolName = resolveAllowedPoolName(taskName, taskScheduleDefaultPoolName, "apollo default");
+        if (StringUtil.isNotEmpty(allowedDefaultPoolName)) {
+            return allowedDefaultPoolName;
+        }
+
+        log.warn("WARN scheduled task pool fallback to built-in default, taskName={}, fallbackPoolName={}", taskName, TASK_DEFAULT_POOL);
+        return TASK_DEFAULT_POOL;
+    }
+
+    private String resolveAllowedPoolName(String taskName, String poolName, String source) {
+        if (StringUtil.isNullOrBlank(poolName)) {
+            return null;
+        }
+
+        String trimmedPoolName = poolName.trim();
+        if (isAllowedPoolName(trimmedPoolName)) {
+            return trimmedPoolName;
+        }
+
+        log.warn("WARN scheduled task pool rejected, taskName={}, source={}, poolName={}, allowedPoolNames={}",
+            taskName, source, trimmedPoolName, taskScheduleAllowedPoolNames);
+        return null;
+    }
+
+    private boolean isAllowedPoolName(String poolName) {
+        return !CollectionUtils.isEmpty(taskScheduleAllowedPoolNames) && taskScheduleAllowedPoolNames.contains(poolName);
+    }
+}

