+        poolMap.put("taskA", "aps_task_execute_pool");
+        ScheduledTaskExecutorResolver resolver = resolver(true, false, "aps_task_execute_pool", poolMap, "aps_task_execute_pool", "aps_task_long_pool");
+
+        String poolName = resolver.resolvePoolName("taskA", "aps_task_long_pool");
+
+        Assert.assertEquals("aps_task_execute_pool", poolName);
