+    public void shouldUseAllowedMapPool() throws Exception {
+        Map<String, String> poolMap = new HashMap<>();
+        poolMap.put("taskA", "aps_task_long_pool");
+        ScheduledTaskExecutorResolver resolver = resolver(true, false, "aps_task_execute_pool", poolMap, "aps_task_execute_pool", "aps_task_long_pool");
