+        setField(resolver, "taskScheduleExecuteOptimizeSwitch", optimizeSwitch);
+        setField(resolver, "taskScheduleParamPoolSwitch", paramSwitch);
+        setField(resolver, "taskScheduleDefaultPoolName", defaultPoolName);
