+
+```java
+package com.qihoo.finance.aps.common.task.service;
+
+import com.ctrip.framework.apollo.spring.annotation.ApolloJsonValue;
+import com.qihoo.finance.aps.v4.utils.StringUtil;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.beans.factory.annotation.Value;
+import org.springframework.stereotype.Service;
+import org.springframework.util.CollectionUtils;
+
+import java.util.Collections;
+import java.util.List;
+import java.util.Map;
+
+@Slf4j
+@Service
+public class ScheduledTaskExecutorResolver {
+    public static final String TASK_DEFAULT_POOL = "task_default_pool";
+
+    @Value("${aps.apollo.function.switch.taskScheduleExecuteOptimizeSwitch:false}")
+    private boolean taskScheduleExecuteOptimizeSwitch;
+
+    @Value("${aps.apollo.function.switch.taskScheduleParamPoolSwitch:false}")
+    private boolean taskScheduleParamPoolSwitch;
+
+    @Value("${aps.apollo.config.taskScheduleDefaultPoolName:aps_task_execute_pool}")
+    private String taskScheduleDefaultPoolName;
+
+    @ApolloJsonValue("${aps.apollo.config.taskSchedulePoolNameMap:{}}")
+    private Map<String, String> taskSchedulePoolNameMap;
+
+    @ApolloJsonValue("${aps.apollo.config.taskScheduleAllowedPoolNames:[\"aps_task_execute_pool\"]}")
+    private List<String> taskScheduleAllowedPoolNames;
+
+    public boolean isOptimizeEnabled() {
+        return taskScheduleExecuteOptimizeSwitch;
+    }
+
+    public String resolvePoolName(String taskName, String taskPoolName) {
+        String parameterPool = resolveParameterPool(taskName, taskPoolName);
+        if (!StringUtil.isNullOrBlank(parameterPool)) {
+            return parameterPool;
+        }
+
+        String mappedPool = getPoolFromMapping(taskName);
+        if (!StringUtil.isNullOrBlank(mappedPool)) {
+            return mappedPool;
+        }
+
+        String defaultPool = resolveAllowedPool(taskName, taskScheduleDefaultPoolName, "apolloDefault");
+        if (!StringUtil.isNullOrBlank(defaultPool)) {
+            return defaultPool;
+        }
+
+        log.warn("WARN 璋冨害浠诲姟绾跨▼姹犻厤缃棤鏈夋晥鍊?浣跨敤鍐呯疆榛樿绾跨▼姹?taskName={} poolName={}", taskName, TASK_DEFAULT_POOL);
+        return TASK_DEFAULT_POOL;
+    }
+
+    private String resolveParameterPool(String taskName, String taskPoolName) {
+        if (!taskScheduleParamPoolSwitch || StringUtil.isNullOrBlank(taskPoolName)) {
+            return null;
+        }
+        return resolveAllowedPool(taskName, taskPoolName, "taskParam");
+    }
+
+    private String getPoolFromMapping(String taskName) {
+        Map<String, String> poolNameMap = taskSchedulePoolNameMap == null ? Collections.<String, String>emptyMap() : taskSchedulePoolNameMap;
+        return resolveAllowedPool(taskName, poolNameMap.get(taskName), "apolloMapping");
+    }
+
+    private String resolveAllowedPool(String taskName, String poolName, String source) {
+        if (StringUtil.isNullOrBlank(poolName)) {
+            return null;
+        }
+
+        if (!isAllowed(poolName)) {
+            log.warn("WARN 璋冨害浠诲姟绾跨▼姹犳湭鍛戒腑鐧藉悕鍗?taskName={} source={} poolName={}", taskName, source, poolName);
+            return null;
+        }
+
+        return poolName;
+    }
+
+    private boolean isAllowed(String poolName) {
+        return !CollectionUtils.isEmpty(taskScheduleAllowedPoolNames) && taskScheduleAllowedPoolNames.contains(poolName);
+    }
+}
+```
