+                firstExportEventTime = now;
+            }
+            lastExportEventTime = now;
+            ProviderExportEvent exportEvent = ProviderExportEvent.from(serviceBean, now, firstExportEventTime);
+            exportEvents.put(exportEvent.serviceKey, exportEvent);
+        }
+    }
