+    private void summarize() {
+        List<String> issues = new ArrayList<String>();
+        try {
+            ProviderSummary summary = buildSummary();
+
+            log.info("[StartupDiagnostics][DubboProvider] serviceBeanCount={} exportedCount={} unexportedCount={} notExportedCount={} exportedWithoutUrlCount={} delayCount={} eventCount={} exportWindowMs={} firstEventOffsetMs={} lastEventOffsetMs={}",
+                    summary.serviceBeanCount, summary.exportedCount, summary.unexportedCount, summary.notExportedCount,
