+        final int initialDelayMs = normalizeGateInitialDelayMs(gateInitialDelayMs);
+        final int intervalMs = normalizeGateIntervalMs(gateIntervalMs);
+        final int maxWaitMs = normalizeGateMaxWaitMs(gateMaxWaitMs);
+        executor.schedule(new Runnable() {
+            @Override
+            public void run() {
+                runGateCheck(gateStartTime, intervalMs, maxWaitMs);
+            }
+        }, initialDelayMs, TimeUnit.MILLISECONDS);
+    }
+
+    private void scheduleNextGateCheck(final long gateStartTime, final int intervalMs, final int maxWaitMs) {
