+                    result.passed, elapsedMs, summary.serviceBeanCount, result.expectedCount, summary.exportedCount,
+                    formatRatio(result.exportedRatio), summary.notExportedCount, summary.unexportedCount,
+                    summary.exportedWithoutUrlCount, summary.eventCount);
