+    private ProviderSummary buildSummary() {
+        String[] serviceBeanNames = beanFactory.getBeanNamesForType(ServiceBean.class, false, false);
+        List<ProviderExportStatus> statuses = buildStatuses(serviceBeanNames);
+        return ProviderSummary.from(statuses, snapshotEvents(), firstExportEventTime, lastExportEventTime);
+    }
+
+    private List<ProviderExportStatus> buildStatuses(String[] serviceBeanNames) {
+        if (serviceBeanNames == null || serviceBeanNames.length == 0) {
+            return Collections.emptyList();
+        }
+
+        List<ProviderExportStatus> statuses = new ArrayList<ProviderExportStatus>(serviceBeanNames.length);
+        for (String beanName : serviceBeanNames) {
+            Object singleton = beanFactory.containsSingleton(beanName) ? beanFactory.getSingleton(beanName) : null;
+            if (singleton instanceof ServiceBean) {
+                statuses.add(ProviderExportStatus.from(beanName, (ServiceBean) singleton));
+            } else {
+                statuses.add(ProviderExportStatus.notCreated(beanName));
+            }
+        }
+        return statuses;
+    }
+
+    private List<ProviderExportEvent> snapshotEvents() {
+        synchronized (exportEvents) {
+            return new ArrayList<ProviderExportEvent>(exportEvents.values());
+        }
+    }
+
+    private void logTopN(List<ProviderExportEvent> events) {
+        if (events == null || events.isEmpty()) {
+            return;
+        }
+
+        List<ProviderExportEvent> sortedEvents = new ArrayList<ProviderExportEvent>(events);
+        Collections.sort(sortedEvents, new Comparator<ProviderExportEvent>() {
+            @Override
+            public int compare(ProviderExportEvent left, ProviderExportEvent right) {
+                return Long.compare(right.offsetMs, left.offsetMs);
+            }
+        });
+
+        int limit = normalizeTopN(topN, sortedEvents.size());
+        for (int i = 0; i < limit; i++) {
+            ProviderExportEvent event = sortedEvents.get(i);
+            log.info("[StartupDiagnostics][DubboProvider][TopN] rank={} interface={} path={} offsetMs={} exportedUrlCount={}",
+                    i + 1, event.interfaceName, event.path, event.offsetMs, event.exportedUrlCount);
+        }
+    }
+
+    private void appendIssues(List<String> issues, ProviderSummary summary) {
+        if (summary.serviceBeanCount == 0) {
+            issues.add("dubbo.provider.serviceBeans.empty");
+        }
+        if (summary.notExportedCount > 0) {
+            issues.add("dubbo.provider.notExportedCount=" + summary.notExportedCount);
+        }
+        if (summary.unexportedCount > 0) {
+            issues.add("dubbo.provider.unexportedCount=" + summary.unexportedCount);
+        }
+        if (summary.exportedWithoutUrlCount > 0) {
+            issues.add("dubbo.provider.exportedWithoutUrlCount=" + summary.exportedWithoutUrlCount);
+        }
+        if (summary.eventCount > 0 && summary.exportedCount > summary.eventCount) {
+            issues.add("dubbo.provider.exportedWithoutEvent=" + (summary.exportedCount - summary.eventCount));
+        }
+    }
+
+    private int normalizeTopN(int configuredTopN, int size) {
+        int normalizedTopN = configuredTopN <= 0 ? DEFAULT_TOP_N : configuredTopN;
+        return Math.min(normalizedTopN, size);
+    }
+
+    private int normalizeSummaryDelayMs(int configuredSummaryDelayMs) {
+        return configuredSummaryDelayMs < 0 ? DEFAULT_SUMMARY_DELAY_MS : configuredSummaryDelayMs;
+    }
+
+    private int normalizeGateInitialDelayMs(int configuredInitialDelayMs) {
+        return configuredInitialDelayMs < 0 ? DEFAULT_GATE_INITIAL_DELAY_MS : configuredInitialDelayMs;
+    }
+
+    private int normalizeGateIntervalMs(int configuredIntervalMs) {
+        return configuredIntervalMs <= 0 ? DEFAULT_GATE_INTERVAL_MS : configuredIntervalMs;
+    }
+
+    private int normalizeGateMaxWaitMs(int configuredMaxWaitMs) {
+        return configuredMaxWaitMs < 0 ? DEFAULT_GATE_MAX_WAIT_MS : configuredMaxWaitMs;
+    }
+
+    private int normalizeGateExpectedCount(int configuredExpectedCount) {
+        return configuredExpectedCount < 0 ? DEFAULT_GATE_EXPECTED_COUNT : configuredExpectedCount;
+    }
+
+    private double normalizeGateMinExportedRatio(double configuredMinExportedRatio) {
+        if (Double.isNaN(configuredMinExportedRatio)) {
+            return DEFAULT_GATE_MIN_EXPORTED_RATIO;
+        }
+        if (configuredMinExportedRatio < 0D) {
+            return 0D;
+        }
+        if (configuredMinExportedRatio > 1D) {
+            return 1D;
+        }
+        return configuredMinExportedRatio;
+    }
+
+    private static String formatRatio(double ratio) {
+        return String.format(Locale.ROOT, "%.4f", ratio);
+    }
+
+    @Override
+    public void destroy() {
+        executor.shutdownNow();
+    }
+
+    private static String serviceKey(ServiceBean serviceBean) {
