+
+            List<String> notReadySamples = buildNotReadySamples(summary.statuses, sampleLimit);
+            return new ProviderGateResult(issues.isEmpty(), expectedCount, minExportedRatio, exportedRatio,
+                    issues, notReadySamples);
+        }
+
+        private static List<String> buildNotReadySamples(List<ProviderExportStatus> statuses, int sampleLimit) {
+            if (statuses == null || statuses.isEmpty() || sampleLimit <= 0) {
+                return Collections.emptyList();
+            }
+            List<String> samples = new ArrayList<String>();
+            for (ProviderExportStatus status : statuses) {
+                if (!status.exported || status.unexported || status.exportedUrlCount <= 0) {
+                    samples.add(status.beanName + "=" + status.serviceKey);
+                    if (samples.size() >= sampleLimit) {
+                        break;
+                    }
+                }
+            }
+            return samples;
+        }
+    }
+}

