+                handleGateTimeout(result, elapsedMs);
+                return;
+            }
+            scheduleNextGateCheck(gateStartTime, intervalMs, maxWaitMs);
+        } catch (Exception e) {
+            log.error("[StartupDiagnostics][DubboProvider][Gate] unexpected gate error elapsedMs={}", elapsedMs, e);
+            if (gateFailFast) {
