+            }
+            if (elapsedMs < maxWaitMs) {
+                scheduleNextGateCheck(gateStartTime, intervalMs, maxWaitMs);
+            }
+        }
+    }
+
+    private void handleGateTimeout(ProviderGateResult result, long elapsedMs) {
+        log.warn("[StartupDiagnostics][DubboProvider][Gate] timeout elapsedMs={} issues={} samples={}",
+                elapsedMs, result.issues, result.notReadySamples);
