+    private ProviderSummary buildSummary() {
+        String[] serviceBeanNames = beanFactory.getBeanNamesForType(ServiceBean.class, false, false);
+        List<ProviderExportStatus> statuses = buildStatuses(serviceBeanNames);
+        return ProviderSummary.from(statuses, snapshotEvents(), firstExportEventTime, lastExportEventTime);
+    }
+
+    private List<ProviderExportStatus> buildStatuses(String[] serviceBeanNames) {
+        if (serviceBeanNames == null || serviceBeanNames.length == 0) {
+            return Collections.emptyList();
+        }
+
+        List<ProviderExportStatus> statuses = new ArrayList<ProviderExportStatus>(serviceBeanNames.length);
+        for (String beanName : serviceBeanNames) {
+            Object singleton = beanFactory.containsSingleton(beanName) ? beanFactory.getSingleton(beanName) : null;
+            if (singleton instanceof ServiceBean) {
+                statuses.add(ProviderExportStatus.from(beanName, (ServiceBean) singleton));
+            } else {
+                statuses.add(ProviderExportStatus.notCreated(beanName));
+            }
+        }
