+            this.passed = passed;
+            this.expectedCount = expectedCount;
+            this.minExportedRatio = minExportedRatio;
+            this.exportedRatio = exportedRatio;
+            this.issues = issues;
+            this.notReadySamples = notReadySamples;
+        }
+
+        private static ProviderGateResult from(ProviderSummary summary, int expectedCount, double minExportedRatio,
