+            List<String> issues = new ArrayList<String>();
+            if (summary.serviceBeanCount == 0) {
+                issues.add("dubbo.provider.serviceBeans.empty");
+            }
+            if (expectedCount > 0 && summary.serviceBeanCount != expectedCount) {
+                issues.add("dubbo.provider.expectedCount=" + expectedCount + ",actualCount=" + summary.serviceBeanCount);
+            }
+            if (summary.notExportedCount > 0) {
+                issues.add("dubbo.provider.notExportedCount=" + summary.notExportedCount);
+            }
+            if (summary.unexportedCount > 0) {
+                issues.add("dubbo.provider.unexportedCount=" + summary.unexportedCount);
+            }
+            if (summary.exportedWithoutUrlCount > 0) {
+                issues.add("dubbo.provider.exportedWithoutUrlCount=" + summary.exportedWithoutUrlCount);
+            }
+
+            double exportedRatio = summary.serviceBeanCount == 0 ? 0D
+                    : (double) summary.exportedCount / (double) summary.serviceBeanCount;
+            if (exportedRatio < minExportedRatio) {
+                issues.add("dubbo.provider.exportedRatio=" + formatRatio(exportedRatio)
