+        }
+
+        private static List<String> buildNotReadySamples(List<ProviderExportStatus> statuses, int sampleLimit) {
+            if (statuses == null || statuses.isEmpty() || sampleLimit <= 0) {
+                return Collections.emptyList();
+            }
+            List<String> samples = new ArrayList<String>();
+            for (ProviderExportStatus status : statuses) {
