+package com.qihoo.finance.aps.common.dubbo;
+
+import com.alibaba.dubbo.config.spring.ReferenceBean;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.beans.BeansException;
+import org.springframework.beans.factory.config.BeanDefinition;
+import org.springframework.beans.factory.config.BeanFactoryPostProcessor;
+import org.springframework.beans.factory.config.ConfigurableListableBeanFactory;
+import org.springframework.context.EnvironmentAware;
+import org.springframework.core.Ordered;
+import org.springframework.core.env.Environment;
+import org.springframework.stereotype.Component;
+
+/**
+ * Optional early switch for making Dubbo reference definitions lazy.
+ */
+@Slf4j
+@Component
+public class DubboReferenceBeanDefinitionPostProcessor implements BeanFactoryPostProcessor, EnvironmentAware, Ordered {
+
+    static final String REFERENCE_BEAN_CLASS_NAME = ReferenceBean.class.getName();
+    private static final String TONG_DUN_CMSX_CREDIT_QUERY_FACADE = "tongDunCmsxCreditQueryFacade";
+    private static final String TONG_DUN_CMSX_CREDIT_QUERY_FACADE_UNIFIED = "tongDunCmsxCreditQueryFacadeUnified";
+
+    private static final String ENABLED_KEY = "aps.dubbo.reference.parallel.enabled";
+    private static final String MARK_LAZY_KEY = "aps.dubbo.reference.parallel.mark-lazy";
+
+    private Environment environment;
+
+    @Override
+    public void setEnvironment(Environment environment) {
+        this.environment = environment;
+    }
+
+    @Override
+    public void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) throws BeansException {
+        if (!getBoolean(ENABLED_KEY, true)) {
+            log.info("[DubboReferenceParallel] disabled, skip reference bean definition processing.");
+            return;
+        }
+        if (!getBoolean(MARK_LAZY_KEY, true)) {
+            log.info("[DubboReferenceParallel] mark-lazy is disabled, keep Dubbo reference bean definitions unchanged.");
+            return;
+        }
+
+        int referenceBeanCount = 0;
+        int explicitFactoryReferenceBeanCount = 0;
+        for (String beanName : beanFactory.getBeanDefinitionNames()) {
+            BeanDefinition beanDefinition = beanFactory.getBeanDefinition(beanName);
+            if (isDubboReferenceBean(beanDefinition)) {
+                referenceBeanCount++;
+            } else if (isExplicitFactoryReferenceBean(beanName)) {
+                explicitFactoryReferenceBeanCount++;
+            } else {
+                continue;
+            }
+            beanDefinition.setLazyInit(true);
+        }
+        log.info("[DubboReferenceParallel] marked Dubbo reference bean definitions lazy, referenceBeanCount={}, explicitFactoryReferenceBeanCount={}, total={}",
+                referenceBeanCount, explicitFactoryReferenceBeanCount, referenceBeanCount + explicitFactoryReferenceBeanCount);
+    }
+
+    @Override
+    public int getOrder() {
+        return Ordered.LOWEST_PRECEDENCE;
+    }
+
+    private boolean getBoolean(String key, boolean defaultValue) {
+        if (environment == null) {
+            return defaultValue;
+        }
+        return environment.getProperty(key, Boolean.class, defaultValue);
+    }
+
+    static boolean isDubboReferenceBean(String beanName, BeanDefinition beanDefinition) {
+        return isDubboReferenceBean(beanDefinition) || isExplicitFactoryReferenceBean(beanName);
+    }
+
+    private static boolean isDubboReferenceBean(BeanDefinition beanDefinition) {
+        return beanDefinition != null
+                && !beanDefinition.isAbstract()
+                && REFERENCE_BEAN_CLASS_NAME.equals(beanDefinition.getBeanClassName());
+    }
+
+    static boolean isExplicitFactoryReferenceBean(String beanName) {
+        return TONG_DUN_CMSX_CREDIT_QUERY_FACADE.equals(beanName)
+                || TONG_DUN_CMSX_CREDIT_QUERY_FACADE_UNIFIED.equals(beanName);
+    }
+}

