+
+    @Override
+    public void onApplicationEvent(ContextRefreshedEvent event) {
+        if (!enabled) {
+            log.info("[DubboReferenceParallel] initializer is disabled.");
+            return;
+        }
+        if (!initialized.compareAndSet(false, true)) {
+            return;
+        }
+
+        ReferenceBeanNames referenceBeanNames = findDubboReferenceBeanNames();
+        if (referenceBeanNames.isEmpty()) {
+            log.info("[DubboReferenceParallel] no Dubbo reference bean found.");
+            return;
+        }
+        List<String> beanNames = referenceBeanNames.beanNames;
+
+        int actualThreads = normalizeThreads(threads, beanNames.size());
+        int actualAwaitSeconds = normalizeAwaitSeconds(awaitSeconds);
+        executorService = Executors.newFixedThreadPool(actualThreads, new DubboReferenceThreadFactory());
+
+        long start = System.currentTimeMillis();
+        log.info("[DubboReferenceParallel] start initializing Dubbo references, count={}, referenceBeanCount={}, explicitFactoryReferenceBeanCount={}, threads={}, awaitSeconds={}, failFast={}",
+                beanNames.size(), referenceBeanNames.referenceBeanCount, referenceBeanNames.explicitFactoryReferenceBeanCount,
+                actualThreads, actualAwaitSeconds, failFast);
+
+        ExecutorCompletionService<ReferenceInitResult> completionService =
+                new ExecutorCompletionService<ReferenceInitResult>(executorService);
+        submitTasks(completionService, beanNames);
+        List<ReferenceInitResult> failures = waitForResults(completionService, beanNames, actualAwaitSeconds);
+        shutdownExecutorGracefully();
+        long cost = System.currentTimeMillis() - start;
+
+        if (failures.isEmpty()) {
+            log.info("[DubboReferenceParallel] finished initializing Dubbo references, count={}, costMs={}", beanNames.size(), cost);
+            return;
+        }
+
+        log.error("[DubboReferenceParallel] failed initializing Dubbo references, total={}, failed={}, costMs={}, failures={}",
+                beanNames.size(), failures.size(), cost, failures);
+        if (failFast) {
+            throw new IllegalStateException("[DubboReferenceParallel] failed initializing Dubbo references: " + failures);
+        }
+    }
+
+    private ReferenceBeanNames findDubboReferenceBeanNames() {
+        ConfigurableListableBeanFactory beanFactory = getBeanFactory();
+        if (beanFactory == null) {
+            return ReferenceBeanNames.empty();
+        }
+
+        List<String> beanNames = new ArrayList<String>();
+        int referenceBeanCount = 0;
+        int explicitFactoryReferenceBeanCount = 0;
+        for (String beanName : beanFactory.getBeanDefinitionNames()) {
+            BeanDefinition beanDefinition = beanFactory.getBeanDefinition(beanName);
+            if (DubboReferenceBeanDefinitionPostProcessor.isDubboReferenceBean(beanName, beanDefinition)) {
+                beanNames.add(beanName);
+                if (DubboReferenceBeanDefinitionPostProcessor.isExplicitFactoryReferenceBean(beanName)) {
+                    explicitFactoryReferenceBeanCount++;
+                } else {
+                    referenceBeanCount++;
+                }
+            }
+        }
+        return new ReferenceBeanNames(beanNames, referenceBeanCount, explicitFactoryReferenceBeanCount);
+    }
+
+    private ConfigurableListableBeanFactory getBeanFactory() {
+        if (applicationContext == null || !(applicationContext instanceof ConfigurableApplicationContext)) {
+            return null;
+        }
+        return ((ConfigurableApplicationContext) applicationContext).getBeanFactory();
+    }
+
+    private void submitTasks(ExecutorCompletionService<ReferenceInitResult> completionService, List<String> beanNames) {
+        for (final String beanName : beanNames) {
+            completionService.submit(new Callable<ReferenceInitResult>() {
+                @Override
+                public ReferenceInitResult call() {
+                    long start = System.currentTimeMillis();
+                    try {
+                        applicationContext.getBean(beanName);
+                        applicationContext.getBean(FACTORY_BEAN_PREFIX + beanName);
+                        long cost = System.currentTimeMillis() - start;
+                        log.debug("[DubboReferenceParallel] initialized reference beanName={}, costMs={}", beanName, cost);
+                        return ReferenceInitResult.success(beanName, cost);
+                    } catch (Throwable throwable) {
+                        long cost = System.currentTimeMillis() - start;
+                        log.error("[DubboReferenceParallel] failed to initialize reference beanName={}, costMs={}", beanName, cost, throwable);
+                        return ReferenceInitResult.failure(beanName, cost, throwable);
+                    }
+                }
+            });
+        }
+    }
+
+    private List<ReferenceInitResult> waitForResults(ExecutorCompletionService<ReferenceInitResult> completionService,
+                                                     List<String> beanNames,
+                                                     int actualAwaitSeconds) {
+        long deadline = System.currentTimeMillis() + TimeUnit.SECONDS.toMillis(actualAwaitSeconds);
+        List<ReferenceInitResult> failures = new ArrayList<ReferenceInitResult>();
+        Set<String> completedBeanNames = new HashSet<String>();
+
+        for (int i = 0; i < beanNames.size(); i++) {
+            long remainMillis = deadline - System.currentTimeMillis();
+            if (remainMillis <= 0) {
+                addTimeoutFailures(beanNames, completedBeanNames, failures, actualAwaitSeconds);
+                shutdownExecutorNow();
+                break;
+            }
+            try {
+                java.util.concurrent.Future<ReferenceInitResult> future = completionService.poll(remainMillis, TimeUnit.MILLISECONDS);
+                if (future == null) {
+                    addTimeoutFailures(beanNames, completedBeanNames, failures, actualAwaitSeconds);
+                    shutdownExecutorNow();
+                    break;
+                }
+                ReferenceInitResult result = future.get();
+                completedBeanNames.add(result.beanName);
+                if (!result.success) {
+                    failures.add(result);
+                }
+            } catch (InterruptedException e) {
+                Thread.currentThread().interrupt();
+                failures.add(ReferenceInitResult.failure("interrupted", actualAwaitSeconds * 1000L, e));
+                shutdownExecutorNow();
+                break;
+            } catch (Exception e) {
+                failures.add(ReferenceInitResult.failure("future", actualAwaitSeconds * 1000L, e));
+            }
+        }
+        return failures;
+    }
+
+    private void addTimeoutFailures(List<String> beanNames,
+                                    Set<String> completedBeanNames,
+                                    List<ReferenceInitResult> failures,
+                                    int actualAwaitSeconds) {
+        for (String beanName : beanNames) {
+            if (!completedBeanNames.contains(beanName)) {
+                failures.add(ReferenceInitResult.failure(beanName, actualAwaitSeconds * 1000L,
+                        new IllegalStateException("await timeout seconds=" + actualAwaitSeconds)));
+            }
+        }
+    }
+
+    private int normalizeThreads(int configuredThreads, int referenceCount) {
+        int normalizedThreads = configuredThreads <= 0 ? DEFAULT_THREADS : configuredThreads;
+        return Math.max(1, Math.min(normalizedThreads, referenceCount));
+    }
+
+    private int normalizeAwaitSeconds(int configuredAwaitSeconds) {
+        return configuredAwaitSeconds <= 0 ? DEFAULT_AWAIT_SECONDS : configuredAwaitSeconds;
+    }
+
+    @Override
+    public void destroy() {
+        shutdownExecutorNow();
+    }
+
+    private void shutdownExecutorGracefully() {
+        ExecutorService executor = executorService;
+        if (executor != null) {
+            executor.shutdown();
+        }
+    }
+
+    private void shutdownExecutorNow() {
+        ExecutorService executor = executorService;
+        if (executor != null) {
+            executor.shutdownNow();
+        }
+    }
+
+    private static class DubboReferenceThreadFactory implements ThreadFactory {
+
+        private final AtomicInteger threadIndex = new AtomicInteger(1);
+
+        @Override
+        public Thread newThread(Runnable runnable) {
+            Thread thread = new Thread(runnable, "aps-dubbo-reference-init-" + threadIndex.getAndIncrement());
+            thread.setDaemon(true);
+            return thread;
+        }
+    }
+
+    private static class ReferenceInitResult {
+
+        private final String beanName;
+        private final boolean success;
+        private final long costMs;
+        private final String errorType;
+        private final String errorMessage;
+
+        private ReferenceInitResult(String beanName, boolean success, long costMs, String errorType, String errorMessage) {
+            this.beanName = beanName;
+            this.success = success;
+            this.costMs = costMs;
+            this.errorType = errorType;
+            this.errorMessage = errorMessage;
+        }
+
+        private static ReferenceInitResult success(String beanName, long costMs) {
+            return new ReferenceInitResult(beanName, true, costMs, null, null);
+        }
+
+        private static ReferenceInitResult failure(String beanName, long costMs, Throwable throwable) {
+            return new ReferenceInitResult(beanName, false, costMs,
+                    throwable == null ? null : throwable.getClass().getName(),
+                    throwable == null ? null : throwable.getMessage());
+        }
+
+        @Override
+        public String toString() {
+            return "ReferenceInitResult{"
+                    + "beanName='" + beanName + '\''
+                    + ", success=" + success
+                    + ", costMs=" + costMs
+                    + ", errorType='" + errorType + '\''
+                    + ", errorMessage='" + errorMessage + '\''
+                    + '}';
+        }
+    }
+
+    private static class ReferenceBeanNames {
+
+        private final List<String> beanNames;
+        private final int referenceBeanCount;
+        private final int explicitFactoryReferenceBeanCount;
+
+        private ReferenceBeanNames(List<String> beanNames, int referenceBeanCount, int explicitFactoryReferenceBeanCount) {
+            this.beanNames = beanNames;
+            this.referenceBeanCount = referenceBeanCount;
+            this.explicitFactoryReferenceBeanCount = explicitFactoryReferenceBeanCount;
+        }
+
+        private static ReferenceBeanNames empty() {
+            return new ReferenceBeanNames(Collections.<String>emptyList(), 0, 0);
+        }
+
+        private boolean isEmpty() {
+            return beanNames == null || beanNames.isEmpty();
+        }
+    }
+}

