+package com.qihoo.finance.aps.modules.kafka.config;
+
+import com.qihoo.finance.aps.common.apollo.ApsApolloConfiguration;
+import com.qihoo.finance.aps.modules.mq.comsumer.ObWriteConsumer;
+import com.qihoo.finance.aps.modules.mq.rocketmq.base.IEventBusConsumer;
+import com.qihoo.finance.aps.modules.mq.rocketmq.base.MqTopicEnum;
+import com.qihoo.finance.aps.modules.mq.rocketmq.base.MqTopicTagEnum;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.beans.factory.annotation.Value;
+import org.springframework.context.ApplicationContext;
+import org.springframework.context.ApplicationListener;
+import org.springframework.context.annotation.Lazy;
+import org.springframework.context.event.ContextRefreshedEvent;
+import org.springframework.stereotype.Component;
+
+import javax.annotation.Resource;
+import java.util.ArrayList;
+import java.util.HashSet;
+import java.util.LinkedHashMap;
+import java.util.LinkedHashSet;
+import java.util.List;
+import java.util.Map;
+import java.util.Set;
+import java.util.concurrent.atomic.AtomicBoolean;
+
+/**
+ * Startup config validator for Kafka and EventBus/RocketMQ metadata.
+ * It only reads local configuration and Spring bean definitions, and never starts external clients.
+ */
+@Slf4j
+@Component
+@Lazy(false)
+public class KafkaConfigValidator implements ApplicationListener<ContextRefreshedEvent> {
+
+    private static final String APV_KAFKA_DEFAULT_TOPIC = "api_qingtui_offline";
+    private static final String OB_WRITE_ENUM_NAME = "APS_OB_WRITE_TAG_MQ";
+
+    private final AtomicBoolean validated = new AtomicBoolean(false);
+
+    @Resource
+    private ApsApolloConfiguration apsApolloConfiguration;
+    @Resource
+    private ApplicationContext applicationContext;
+
+    @Value("${aps.startup.config.validator.enabled:true}")
+    private boolean enabled;
+    @Value("${aps.startup.config.validator.fail-fast:false}")
+    private boolean failFast;
+
+    @Override
+    public void onApplicationEvent(ContextRefreshedEvent event) {
+        if (!enabled) {
+            log.info("[StartupDiagnostics][ConfigValidator] validator is disabled.");
+            return;
+        }
+        if (!validated.compareAndSet(false, true)) {
+            return;
+        }
+
+        List<String> issues = new ArrayList<>();
+        try {
+            validateKafkaConfig(issues);
+            validateMqConfig(issues);
+        } catch (Exception e) {
+            issues.add("validatorUnexpectedError=" + e.getClass().getSimpleName());
+            log.error("[StartupDiagnostics][ConfigValidator] unexpected validation error", e);
+        }
+
+        if (issues.isEmpty()) {
+            log.info("[StartupDiagnostics][ConfigValidator] finished with no issue.");
+            return;
+        }
+
+        log.warn("[StartupDiagnostics][ConfigValidator] finished with issues={}", issues);
+        if (failFast) {
+            throw new IllegalStateException("[StartupDiagnostics][ConfigValidator] " + issues);
+        }
+    }
+
+    private void validateKafkaConfig(List<String> issues) {
+        List<String> topics = apsApolloConfiguration.getApvKafkaConsumerTopic();
+        List<String> blankTopics = new ArrayList<>();
+        Set<String> seenTopics = new HashSet<>();
+        Set<String> duplicateTopics = new LinkedHashSet<>();
+        List<String> whitespaceTopics = new ArrayList<>();
+        List<String> suspiciousDefaultTopics = new ArrayList<>();
+
+        if (topics == null || topics.isEmpty()) {
+            issues.add("kafka.apv.topics.empty");
+        } else {
+            for (String topic : topics) {
+                if (isBlank(topic)) {
+                    blankTopics.add(String.valueOf(topic));
+                    continue;
+                }
+
+                String normalizedTopic = topic.trim();
+                if (!seenTopics.add(normalizedTopic)) {
+                    duplicateTopics.add(normalizedTopic);
+                }
+                if (hasWhitespace(topic)) {
+                    whitespaceTopics.add(topic);
+                }
+                if (APV_KAFKA_DEFAULT_TOPIC.equals(normalizedTopic)) {
+                    suspiciousDefaultTopics.add(normalizedTopic);
+                }
+            }
+        }
+
+        int consumerThreads = apsApolloConfiguration.getApvConsumerThreads();
+        if (consumerThreads <= 0) {
+            issues.add("kafka.apv.consumerThreads.nonPositive=" + consumerThreads);
+        }
+        if (!blankTopics.isEmpty()) {
+            issues.add("kafka.apv.blankTopics=" + blankTopics);
+        }
+        if (!duplicateTopics.isEmpty()) {
+            issues.add("kafka.apv.duplicateTopics=" + duplicateTopics);
+        }
+        if (!whitespaceTopics.isEmpty()) {
+            issues.add("kafka.apv.whitespaceTopics=" + whitespaceTopics);
+        }
+        if (!suspiciousDefaultTopics.isEmpty()) {
+            issues.add("kafka.apv.suspiciousDefaultTopics=" + suspiciousDefaultTopics);
+        }
+
+        log.info("[StartupDiagnostics][Kafka] apvTopicCount={} uniqueTopicCount={} consumerThreads={} blankTopicCount={} duplicateTopicCount={} whitespaceTopicCount={} suspiciousDefaultCount={}",
+            topics == null ? 0 : topics.size(), seenTopics.size(), consumerThreads, blankTopics.size(),
+            duplicateTopics.size(), whitespaceTopics.size(), suspiciousDefaultTopics.size());
+    }
+
+    private void validateMqConfig(List<String> issues) {
+        Map<String, MqTopicEnum> topicCodeMap = buildTopicCodeMap();
+        Map<String, MqTopicTagEnum> topicTagActionMap = new LinkedHashMap<>();
+        Set<String> duplicateTopicTagActions = new LinkedHashSet<>();
+        List<MqTopicTagEnum> blankTopicEnums = new ArrayList<>();
+        List<MqTopicTagEnum> unknownTopicEnums = new ArrayList<>();
+        List<MqTopicTagEnum> blankTagEnums = new ArrayList<>();
+        List<MqTopicTagEnum> blankActionEnums = new ArrayList<>();
+        List<String> invalidHandlerEnums = new ArrayList<>();
+        List<String> missingHandlerBeanEnums = new ArrayList<>();
+
+        for (MqTopicTagEnum topicTagEnum : MqTopicTagEnum.values()) {
+            String topic = topicTagEnum.getTopic();
+            String tag = topicTagEnum.getTag();
+            String action = topicTagEnum.getAction();
+
+            if (isBlank(topic)) {
+                blankTopicEnums.add(topicTagEnum);
+            } else if (!topicCodeMap.containsKey(topic)) {
+                unknownTopicEnums.add(topicTagEnum);
+            }
+            if (isBlank(tag)) {
+                blankTagEnums.add(topicTagEnum);
+            }
+            if (isBlank(action)) {
+                blankActionEnums.add(topicTagEnum);
+            }
+
+            String routeKey = valueOrEmpty(topic) + "|" + valueOrEmpty(tag) + "|" + valueOrEmpty(action);
+            MqTopicTagEnum previous = topicTagActionMap.put(routeKey, topicTagEnum);
+            if (previous != null) {
+                duplicateTopicTagActions.add(previous.name() + "/" + topicTagEnum.name() + "(" + routeKey + ")");
+            }
+
+            Class<?> handlerClass = topicTagEnum.getHandlerClass();
+            if (handlerClass == null || !IEventBusConsumer.class.isAssignableFrom(handlerClass)) {
+                invalidHandlerEnums.add(topicTagEnum.name() + ":" + String.valueOf(handlerClass));
+                continue;
+            }
+
+            String[] beanNames = applicationContext.getBeanNamesForType(handlerClass, true, false);
+            if (beanNames == null || beanNames.length == 0) {
+                missingHandlerBeanEnums.add(topicTagEnum.name() + ":" + handlerClass.getName());
+            }
+        }
+
+        validateObMqConfig(issues);
+        appendMqIssues(issues, blankTopicEnums, unknownTopicEnums, blankTagEnums, blankActionEnums,
+            duplicateTopicTagActions, invalidHandlerEnums, missingHandlerBeanEnums);
+
+        log.info("[StartupDiagnostics][MQ] totalTopicTags={} topicCount={} blankTopicCount={} unknownTopicCount={} blankTagCount={} blankActionCount={} duplicateRouteCount={} invalidHandlerCount={} missingHandlerBeanCount={}",
+            MqTopicTagEnum.values().length, topicCodeMap.size(), blankTopicEnums.size(), unknownTopicEnums.size(),
+            blankTagEnums.size(), blankActionEnums.size(), duplicateTopicTagActions.size(),
+            invalidHandlerEnums.size(), missingHandlerBeanEnums.size());
+        if (!blankActionEnums.isEmpty()) {
+            log.warn("[StartupDiagnostics][MQ] blankActionEnums={}", enumNames(blankActionEnums));
+        }
+    }
+
+    private void validateObMqConfig(List<String> issues) {
+        MqTopicTagEnum obWriteEnum = MqTopicTagEnum.APS_OB_WRITE_TAG_MQ;
+        if (!MqTopicEnum.APS_MQ.getCode().equals(obWriteEnum.getTopic())) {
+            issues.add("mq.ob.topic.unexpected=" + obWriteEnum.getTopic());
+        }
+        if (isBlank(obWriteEnum.getTag())) {
+            issues.add("mq.ob.tag.blank");
+        }
+        if (isBlank(obWriteEnum.getAction())) {
+            issues.add("mq.ob.action.blank");
+        }
+        if (obWriteEnum.getHandlerClass() != ObWriteConsumer.class) {
+            issues.add("mq.ob.handler.unexpected=" + obWriteEnum.getHandlerClass());
+        }
+        if (!IEventBusConsumer.class.isAssignableFrom(obWriteEnum.getHandlerClass())) {
+            issues.add("mq.ob.handler.notIEventBusConsumer=" + obWriteEnum.getHandlerClass());
+        }
+
+        log.info("[StartupDiagnostics][MQ][OB] enum={} topic={} tag={} action={} handler={}",
+            OB_WRITE_ENUM_NAME, obWriteEnum.getTopic(), obWriteEnum.getTag(), obWriteEnum.getAction(),
+            obWriteEnum.getHandlerClass() == null ? null : obWriteEnum.getHandlerClass().getSimpleName());
+    }
+
+    private void appendMqIssues(List<String> issues,
+                                List<MqTopicTagEnum> blankTopicEnums,
+                                List<MqTopicTagEnum> unknownTopicEnums,
+                                List<MqTopicTagEnum> blankTagEnums,
+                                List<MqTopicTagEnum> blankActionEnums,
+                                Set<String> duplicateTopicTagActions,
+                                List<String> invalidHandlerEnums,
+                                List<String> missingHandlerBeanEnums) {
+        if (!blankTopicEnums.isEmpty()) {
+            issues.add("mq.blankTopicEnums=" + enumNames(blankTopicEnums));
+        }
+        if (!unknownTopicEnums.isEmpty()) {
+            issues.add("mq.unknownTopicEnums=" + enumNames(unknownTopicEnums));
+        }
+        if (!blankTagEnums.isEmpty()) {
+            issues.add("mq.blankTagEnums=" + enumNames(blankTagEnums));
+        }
+        if (!blankActionEnums.isEmpty()) {
+            issues.add("mq.blankActionEnums=" + enumNames(blankActionEnums));
+        }
+        if (!duplicateTopicTagActions.isEmpty()) {
+            issues.add("mq.duplicateTopicTagActions=" + duplicateTopicTagActions);
+        }
+        if (!invalidHandlerEnums.isEmpty()) {
+            issues.add("mq.invalidHandlerEnums=" + invalidHandlerEnums);
+        }
+        if (!missingHandlerBeanEnums.isEmpty()) {
+            issues.add("mq.missingHandlerBeanEnums=" + missingHandlerBeanEnums);
+        }
+    }
+
+    private Map<String, MqTopicEnum> buildTopicCodeMap() {
+        Map<String, MqTopicEnum> topicCodeMap = new LinkedHashMap<>();
+        for (MqTopicEnum topicEnum : MqTopicEnum.values()) {
+            topicCodeMap.put(topicEnum.getCode(), topicEnum);
+        }
+        return topicCodeMap;
+    }
+
+    private String enumNames(List<MqTopicTagEnum> enums) {
+        List<String> names = new ArrayList<>();
+        for (MqTopicTagEnum topicTagEnum : enums) {
+            names.add(topicTagEnum.name());
+        }
+        return names.toString();
+    }
+
+    private boolean isBlank(String value) {
+        return value == null || value.trim().isEmpty();
+    }
+
+    private boolean hasWhitespace(String value) {
+        return value != null && value.matches(".*\\s+.*");
+    }
+
+    private String valueOrEmpty(String value) {
+        return value == null ? "" : value;
+    }
+}

